import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"电力市场 · 赛道文件（电改 2.0）","description":"","frontmatter":{},"headers":[],"relativePath":"电力新能源/电力市场/赛道文件.md","filePath":"电力新能源/电力市场/赛道文件.md","lastUpdated":1781535932000}'),n={name:"电力新能源/电力市场/赛道文件.md"};function h(o,t,s,l,i,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="电力市场-·-赛道文件-电改-2-0" tabindex="-1">电力市场 · 赛道文件（电改 2.0） <a class="header-anchor" href="#电力市场-·-赛道文件-电改-2-0" aria-label="Permalink to &quot;电力市场 · 赛道文件（电改 2.0）&quot;">​</a></h1><p><strong>成熟度：</strong> 改革深化期（2026 为&quot;基本建成全国统一电力市场&quot;冲刺年） <strong>PE/VC 重心：</strong> 电力交易 AI、虚拟电厂聚合平台、新型储能、数字监管 <strong>数据来源：</strong> China Energy MCP（现货市场/电价/政策）、国办发〔2026〕4号文 <strong>数据获取：</strong> 2026-06-15</p><hr><h2 id="一、赛道概览" tabindex="-1">一、赛道概览 <a class="header-anchor" href="#一、赛道概览" aria-label="Permalink to &quot;一、赛道概览&quot;">​</a></h2><h3 id="_1-1-政策顶层设计" tabindex="-1">1.1 政策顶层设计 <a class="header-anchor" href="#_1-1-政策顶层设计" aria-label="Permalink to &quot;1.1 政策顶层设计&quot;">​</a></h3><p>2026年2月，国务院办公厅印发《关于完善全国统一电力市场体系的实施意见》（国办发〔2026〕4号文），围绕 5 方面 19 项重点任务，推动全国统一电力市场建设迈入全面深化新阶段。</p><p><strong>核心目标：</strong></p><table tabindex="0"><thead><tr><th>时间节点</th><th>目标</th></tr></thead><tbody><tr><td>2026年</td><td>过半省份现货市场正式运行</td></tr><tr><td>2027年</td><td>全国 VPP 调节能力 2,000 万千瓦+</td></tr><tr><td>2030年</td><td>基本建成全国统一电力市场体系，市场化交易电量占全社会用电量 70%</td></tr><tr><td>2035年</td><td>全面建成全国统一电力市场体系</td></tr></tbody></table><h3 id="_1-2-市场规模" tabindex="-1">1.2 市场规模 <a class="header-anchor" href="#_1-2-市场规模" aria-label="Permalink to &quot;1.2 市场规模&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数据</th><th>说明</th></tr></thead><tbody><tr><td>全国电力市场交易量</td><td>~6万亿度/年</td><td>2025年数据</td></tr><tr><td>市场化交易占比</td><td>~65%</td><td>2026年目标向 70% 靠近</td></tr><tr><td>现货市场省份</td><td>7省正式运行 + 5省连续试运行</td><td>2026年6月</td></tr><tr><td>新型储能装机</td><td><strong>1.36亿千瓦</strong></td><td>2025 年底突破，十四五拉动投资超 2000 亿</td></tr><tr><td>VPP 调节能力</td><td><strong>1,600 万千瓦</strong></td><td>全国已建成 535 个</td></tr><tr><td>车网互动聚合资源</td><td>1,900 万千瓦</td><td>电动汽车灵活性资源</td></tr><tr><td>数据监管覆盖</td><td>全面推行</td><td>2026年重点方向之一</td></tr></tbody></table><hr><h2 id="二、现货市场建设进展" tabindex="-1">二、现货市场建设进展 <a class="header-anchor" href="#二、现货市场建设进展" aria-label="Permalink to &quot;二、现货市场建设进展&quot;">​</a></h2><h3 id="_2-1-省间进度一览" tabindex="-1">2.1 省间进度一览 <a class="header-anchor" href="#_2-1-省间进度一览" aria-label="Permalink to &quot;2.1 省间进度一览&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>已正式运行（7省）        连续结算试运行（5省）       长周期试运行（9省+）</span></span>
<span class="line"><span>─────────────────      ──────────────────       ──────────────────</span></span>
<span class="line"><span> 山西（首批试点）          安徽（预计2026.06转正）     福建  四川  江苏</span></span>
<span class="line"><span> 广东（首批试点）          陕西（预计2026.06转正）     湖南  河南  宁夏</span></span>
<span class="line"><span> 山东（首批试点）          辽宁                       重庆  上海  吉林</span></span>
<span class="line"><span> 甘肃（首批试点）          河北南网</span></span>
<span class="line"><span> 蒙西（首批非试点转正）    南方区域市场（首个跨省区域）</span></span>
<span class="line"><span> 湖北</span></span>
<span class="line"><span> 浙江</span></span></code></pre></div><h3 id="_2-2-现货电价分化态势" tabindex="-1">2.2 现货电价分化态势 <a class="header-anchor" href="#_2-2-现货电价分化态势" aria-label="Permalink to &quot;2.2 现货电价分化态势&quot;">​</a></h3><table tabindex="0"><thead><tr><th>省份</th><th>4月均价(元/MWh)</th><th>特点</th><th>储能/套利空间</th></tr></thead><tbody><tr><td><strong>广东</strong></td><td>637.91</td><td>负荷中心高价，环比+64.8%</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>山东</strong></td><td>280</td><td>新能源渗透率高，低价频现</td><td>⭐⭐⭐</td></tr><tr><td><strong>山西</strong></td><td>230</td><td>时段性供需错配</td><td>⭐⭐⭐</td></tr><tr><td><strong>甘肃</strong></td><td>145.12</td><td>新能源大发，午间地板价</td><td>⭐⭐⭐⭐（价差大）</td></tr><tr><td><strong>辽宁</strong></td><td>127.03</td><td>大幅回落，环比-47.41%</td><td>⭐⭐</td></tr></tbody></table><blockquote><p>💡 <strong>投资含义：</strong> 价差即套利空间。甘肃→广东的跨省套利逻辑（绿电+通道）是电力交易 AI 和 VPP 的核心商业基础。</p></blockquote><hr><h2 id="三、政策利好方向" tabindex="-1">三、政策利好方向 <a class="header-anchor" href="#三、政策利好方向" aria-label="Permalink to &quot;三、政策利好方向&quot;">​</a></h2><h3 id="_3-1-新型储能——从-补充性设施-到-核心支撑" tabindex="-1">3.1 新型储能——从&quot;补充性设施&quot;到&quot;核心支撑&quot; <a class="header-anchor" href="#_3-1-新型储能——从-补充性设施-到-核心支撑" aria-label="Permalink to &quot;3.1 新型储能——从&quot;补充性设施&quot;到&quot;核心支撑&quot;&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>2025 年底装机</td><td>1.36亿千瓦（十四五拉动投资超 2000亿）</td></tr><tr><td>政策定位</td><td>完善容量电价机制，独立储能升级为系统可靠性核心支撑</td></tr><tr><td>收益来源</td><td>现货套利 + 容量电价 + 辅助服务</td></tr><tr><td>VPP 聚合</td><td>储能是 VPP 最大可调资源</td></tr></tbody></table><h3 id="_3-2-虚拟电厂——首次纳入国家级政策框架" tabindex="-1">3.2 虚拟电厂——首次纳入国家级政策框架 <a class="header-anchor" href="#_3-2-虚拟电厂——首次纳入国家级政策框架" aria-label="Permalink to &quot;3.2 虚拟电厂——首次纳入国家级政策框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>2026</th><th>2027E</th><th>2030E</th></tr></thead><tbody><tr><td>调节能力</td><td>1,600万千瓦</td><td>2,000万千瓦</td><td>5,000万千瓦</td></tr><tr><td>聚合商数量</td><td>200+</td><td>—</td><td>—</td></tr><tr><td>政策地位</td><td>国办发〔2026〕4号文：首次纳入</td><td>—</td><td>商业模式成熟</td></tr><tr><td>收益模式</td><td>从单一补贴→市场化多元</td><td>—</td><td>基础电费+市场收益+政策补贴</td></tr></tbody></table><p><strong>各省进展：</strong></p><ul><li>山东：聚合资源超 300万千瓦，单日顶峰电量超 2,000万千瓦时</li><li>上海：最大响应负荷达 116.27万千瓦</li><li>广州：连续三年每年 1000 万专项资金培育市场</li></ul><h3 id="_3-3-新型经营主体入市" tabindex="-1">3.3 新型经营主体入市 <a class="header-anchor" href="#_3-3-新型经营主体入市" aria-label="Permalink to &quot;3.3 新型经营主体入市&quot;">​</a></h3><p>国办发〔2026〕4号文明确：</p><ul><li>推动&quot;沙戈荒&quot;新能源基地各类型电源整体参与</li><li>支持分布式新能源以聚合交易/直接交易参与</li><li><strong>虚拟电厂、智能微电网、可调节负荷</strong>可灵活参与电力市场</li><li>民营企业参与度持续提升——VPP 中 45% 为民营企业</li></ul><h3 id="_3-4-绿电直连-2-0" tabindex="-1">3.4 绿电直连 2.0 <a class="header-anchor" href="#_3-4-绿电直连-2-0" aria-label="Permalink to &quot;3.4 绿电直连 2.0&quot;">​</a></h3><p>2026年5月，发改委/能源局发布多用户绿电直连政策，将绿电直连从单用户专属拓展为多主体共享。截至2026年2月，全国 84 个项目完成审批，新能源总装机 32.59 GW。</p><hr><h2 id="四、pe-vc-机会" tabindex="-1">四、PE/VC 机会 <a class="header-anchor" href="#四、pe-vc-机会" aria-label="Permalink to &quot;四、PE/VC 机会&quot;">​</a></h2><h3 id="_4-1-电力交易-ai" tabindex="-1">4.1 电力交易 AI <a class="header-anchor" href="#_4-1-电力交易-ai" aria-label="Permalink to &quot;4.1 电力交易 AI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th><th>特点</th></tr></thead><tbody><tr><td><strong>清大科越</strong></td><td>电力交易+调度</td><td>Pre-IPO</td><td>软件+算法，壁垒高</td></tr><tr><td><strong>瓦特智能</strong></td><td>AI+电力调度</td><td>A轮</td><td>AI Agent 在电力场景应用</td></tr></tbody></table><p><strong>投资逻辑：</strong></p><ul><li>现货市场全覆盖→电力交易复杂度剧增→AI 辅助报价刚需</li><li>预测准确率每提升 1% = 可见的经济价值</li><li>壁垒：电网接入经验 + 算法精度 + 历史数据</li></ul><h3 id="_4-2-虚拟电厂聚合平台" tabindex="-1">4.2 虚拟电厂聚合平台 <a class="header-anchor" href="#_4-2-虚拟电厂聚合平台" aria-label="Permalink to &quot;4.2 虚拟电厂聚合平台&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th><th>备注</th></tr></thead><tbody><tr><td><strong>浙达能源</strong></td><td>VPP 聚合+储能运营</td><td>B轮</td><td>浙江，资源丰富</td></tr><tr><td><strong>零碳智能</strong></td><td>VPP SaaS</td><td>A轮</td><td>平台模式</td></tr><tr><td><strong>电享科技</strong></td><td>VPP+充电桩聚合</td><td>B轮</td><td>蔚来资本投资</td></tr><tr><td><strong>泰豪软件</strong></td><td>电力市场交易</td><td>上市公司</td><td>—</td></tr><tr><td><strong>海澜智云</strong></td><td>工业能效+VPP</td><td>B轮</td><td>江苏</td></tr><tr><td><strong>电管家</strong></td><td>分布式能源聚合</td><td>B轮</td><td>—</td></tr><tr><td><strong>兆瓦云</strong></td><td>VPP 运营+交易</td><td>A轮</td><td>华北</td></tr></tbody></table><h3 id="_4-3-投资热度矩阵" tabindex="-1">4.3 投资热度矩阵 <a class="header-anchor" href="#_4-3-投资热度矩阵" aria-label="Permalink to &quot;4.3 投资热度矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方向</th><th>1年确定性</th><th>5年空间</th><th>进入时机</th><th>PE/VC 偏好</th></tr></thead><tbody><tr><td>电力交易 AI</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>当前</td><td>技术壁垒+数据壁垒</td></tr><tr><td>VPP 聚合平台</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>当前-2027</td><td>规模效应+平台效应</td></tr><tr><td>分布式储能运营</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>当前</td><td>资产收益模式</td></tr><tr><td>智能电表 AMI</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>短期</td><td>更新换代确定性高</td></tr><tr><td>电力网络安全</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>当前</td><td>合规强制需求</td></tr><tr><td>绿电直连项目</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>当前</td><td>重资产，适合产业资本</td></tr></tbody></table><hr><h2 id="五、关键风险" tabindex="-1">五、关键风险 <a class="header-anchor" href="#五、关键风险" aria-label="Permalink to &quot;五、关键风险&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险</th><th>影响</th><th>缓释</th></tr></thead><tbody><tr><td>各省现货规则差异大，地方保护</td><td>统一市场进度低于预期</td><td>国办文件推进，制度红利持续</td></tr><tr><td>容量电价未全国统一</td><td>储能/灵活性资源收益不确定</td><td>已有路线图，2027年前逐步明确</td></tr><tr><td>绿电直连输电通道费标准未明确</td><td>经济性测算有偏差</td><td>按容量收费新机制已出台</td></tr><tr><td>补贴退坡节奏不确定</td><td>部分项目 IRR 受影响</td><td>转向市场化收益为主</td></tr></tbody></table><hr><h2 id="六、交叉链接" tabindex="-1">六、交叉链接 <a class="header-anchor" href="#六、交叉链接" aria-label="Permalink to &quot;六、交叉链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>智能电网/VPP</strong></td><td><a href="./../智能电网/新兴赛道">新兴赛道</a></td><td>VPP 是电力市场改革的&quot;柔性大脑&quot;</td></tr><tr><td><strong>储能</strong></td><td><a href="./../储能/产业链">产业链</a></td><td>储能是现货市场套利的核心工具</td></tr><tr><td><strong>算电协同</strong></td><td><a href="./../../算电协同/赛道总览">赛道总览</a></td><td>电力市场改革加速算电协同落地</td></tr><tr><td><strong>碳市场</strong></td><td><a href="./../碳市场/赛道文件">赛道文件</a></td><td>碳价+电价的双重市场化联动</td></tr></tbody></table><hr><p><em>创建：2026-06-15 | 数据来源：国办发〔2026〕4号文、China Energy MCP (spot_market, spot_prices)、北极星电力网</em></p>`,48)])])}const g=d(n,[["render",h]]);export{c as __pageData,g as default};
